-- Ken's Hardened V2 Fix

local b64_0xlIII11 = {}
local char_0xIIIIll='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0x11ll11=1,#char_0xIIIIll do b64_0xlIII11[char_0xIIIIll:sub(i_0x11ll11,i_0x11ll11)] = i_0x11ll11 - 1 end

function b64_0xlIII11.dec_0x1llI11(d_0xI11I11)
    d_0xI11I11 = string.gsub(d_0xI11I11, '[^'..char_0xIIIIll..'=]', '')
    local r_0xlI1IIl = {}
    for i_0x11ll11=1, #d_0xI11I11, 4 do
        local c_0xIIIlll = b64_0xlIII11[d_0xI11I11:sub(i_0x11ll11,i_0x11ll11)] or 0
        local c_0xIIlll1 = b64_0xlIII11[d_0xI11I11:sub(i_0x11ll11+1,i_0x11ll11+1)] or 0
        local c_0xIIllIl, c_0xlIl111 = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xI11I11:sub(i_0x11ll11+2,i_0x11ll11+2)
        if ch3 == "=" then has3 = false else c_0xIIllIl = b64_0xlIII11[ch3] or 0 end
        local ch4 = d_0xI11I11:sub(i_0x11ll11+3,i_0x11ll11+3)
        if ch4 == "=" then has4 = false else c_0xlIl111 = b64_0xlIII11[ch4] or 0 end
        local b_0xIIlIlI = c_0xIIIlll * (2^18) + c_0xIIlll1 * (2^12) + c_0xIIllIl * (2^6) + c_0xlIl111
        local b_0xl1l1ll = math.floor(b_0xIIlIlI / (2^16)) % (2^8)
        local b_0xIlIIlI = math.floor(b_0xIIlIlI / (2^8)) % (2^8)
        local b_0xl1lIl1 = b_0xIIlIlI % (2^8)
        table.insert(r_0xlI1IIl, string.char(b_0xl1l1ll))
        if has3 then table.insert(r_0xlI1IIl, string.char(b_0xIlIIlI)) end
        if has4 then table.insert(r_0xlI1IIl, string.char(b_0xl1lIl1)) end
    end
    return table.concat(r_0xlI1IIl)
end


local function bxor_0xlI1l1l(a_0xIIllII,b_0xlI1lll)
    if bit32 then return bit32.bxor(a_0xIIllII,b_0xlI1lll) end
    local r_0xIIIlIl = 0
    for i_0xl1I1lI = 0, 7 do
        local x_0xIlIIII = a_0xIIllII % 2
        local y_0x1III1l = b_0xlI1lll % 2
        if x_0xIlIIII ~= y_0x1III1l then r_0xIIIlIl = r_0xIIIlIl + (2^i_0xl1I1lI) end
        a_0xIIllII = math.floor(a_0xIIllII / 2)
        b_0xlI1lll = math.floor(b_0xlI1lll / 2)
    end
    return r_0xIIIlIl
end


local function bxor_str_0xIlll1I(s_0xllIl1I, k_0xlIIIII)
    local r_0xll1ll1 = {}
    for i_0xlllI1I=1, #s_0xllIl1I do
        local b_0xllll1l = string.byte(s_0xllIl1I, i_0xlllI1I)
        local kb_0xlIIlIl = string.byte(k_0xlIIIII, (i_0xlllI1I-1) % #k_0xlIIIII + 1)
        r_0xll1ll1[i_0xlllI1I] = string.char(bxor_0xlI1l1l(b_0xllll1l, kb_0xlIIlIl))
    end
    return table.concat(r_0xll1ll1)
end


local function getkeys_0xlIIl1I()
    local seed = b64_0xlIII11.dec_0x1llI11("cEZ4UHNBZ2I=")
    local k1_enc = b64_0xlIII11.dec_0x1llI11("JxwPYx4GJjI=")
    local k2_enc = b64_0xlIII11.dec_0x1llI11("CnAuZCYWEVo=")
    return bxor_str_0xIlll1I(k1_enc, seed), bxor_str_0xIlll1I(k2_enc, seed)
end


local function cff_0xl1IIlI(a_0xIIll1l)
    local st_0xl1IIII = 0
    local res_0xIlIllI = a_0xIIll1l
    while true do
        if st_0xl1IIII == 0 then
            res_0xIlIllI = res_0xIlIllI + 1
            st_0xl1IIII = 1
        elseif st_0xl1IIII == 1 then
            res_0xIlIllI = res_0xIlIllI * 2
            st_0xl1IIII = 2
        elseif st_0xl1IIII == 2 then
            res_0xIlIllI = res_0xIlIllI - 3
            st_0xl1IIII = 3
        else
            break
        end
    end
    return res_0xIlIllI
end


local function chain_0x1l1llI(x) return x*2 end
local function chain_0xIl1I11(x) return chain_0x1l1llI(x)+1 end


local d_0xIlllll = {
  {op=255, val="", is_enc=true},
}
local pc_0xIIlI1I = 1
local stk_0x1l1Ill = {}
stk_0x1l1Ill._jmp = nil


local disp_0x1lIIlI = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xlIIl1I()

local state_0xIIIII1 = 0
while true do
    if state_0xIIIII1 == 0 then  -- FETCH
        if pc_0xIIlI1I > #d_0xIlllll then break end
        local inst = d_0xIlllll[pc_0xIIlI1I]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xlIII11.dec_0x1llI11(val)
            d = bxor_str_0xIlll1I(d, k2)
            val = bxor_str_0xIlll1I(d, k1)
        end
        stk_0x1l1Ill._jmp = nil
        pc_0xIIlI1I = pc_0xIIlI1I + 1
        cur_op_0x1lIlll = opcode
        cur_val_0xl1IIll = val
        state_0xIIIII1 = 1

    elseif state_0xIIIII1 == 1 then  -- EXECUTE
        local handler = disp_0x1lIIlI[cur_op_0x1lIlll]
        if handler then
            handler(stk_0x1l1Ill, cur_val_0xl1IIll)
        end
        if stk_0x1l1Ill._jmp then
            pc_0xIIlI1I = pc_0xIIlI1I + stk_0x1l1Ill._jmp
        end
        state_0xIIIII1 = 0
    else
        break
    end
end
